prompt.format:
{{
    "insights": [
        {{
            "id": "unique_insight_identifier",
            "type": "prediction|opportunity|risk|trend|recommendation",
            "category": "issue_escalation|opportunity_identification|team_dynamics|project_health|communication|workflow",
            "title": "Brief descriptive title",
            "description": "Detailed description of the insight",
            "supporting_evidence": [
                "Specific data points, quotes, or patterns that support this insight"
            ],
            "confidence_level": 0.85,
            "novelty_score": 0.72,
            "impact_level": "low|medium|high|critical",
            "urgency": "low|medium|high|immediate",
            "timeframe": "when this insight applies or when action is needed",
            "predicted_outcome": "what is likely to happen if no action is taken",
            "success_probability": 0.8,
            "entities_affected": ["person_id", "project_id", "team_id"],
            "actionable_steps": [
                "Specific actions that can be taken based on this insight"
            ],
            "success_metrics": [
                "How to measure if acting on this insight was successful"
            ],
            "related_patterns": ["pattern_id_1", "pattern_id_2"],
            "risk_factors": [
                "What could go wrong or limit the success of this insight"
            ]
        }}
    ],
    "predictions": [
        {{
            "prediction_id": "unique_prediction_identifier",
            "prediction": "What is likely to happen",
            "probability": 0.85,
            "confidence_interval": "75%-95%",
            "timeframe": "when this is expected to occur",
            "category": "issue_escalation|opportunity|risk_materialization|trend_continuation",
            "severity": "low|medium|high|critical",
            "supporting_insights": ["insight_id_1", "insight_id_2"],
            "early_indicators": [
                "Signs to watch for that would confirm this prediction"
            ],
            "mitigation_strategies": [
                "Actions that could prevent or minimize negative outcomes"
            ],
            "opportunity_actions": [
                "Actions to capitalize on positive predictions"
            ]
        }}
    ],
    "recommendations": [
        {{
            "recommendation_id": "unique_recommendation_identifier",
            "title": "Brief recommendation title",
            "description": "Detailed recommendation",
            "priority": "low|medium|high|critical",
            "effort_required": "low|medium|high",
            "expected_impact": "description of expected positive impact",
            "implementation_steps": [
                "Step-by-step implementation guide"
            ],
            "timeline": "recommended timeline for implementation",
            "resources_needed": [
                "What resources, people, or tools are needed"
            ],
            "success_criteria": [
                "How to measure successful implementation"
            ],
            "supporting_insights": ["insight_id_1", "insight_id_2"]
        }}
    ],
    "summary": {{
        "total_insights": 10,
        "high_confidence_insights": 7,
        "critical_issues_predicted": 1,
        "opportunities_identified": 3,
        "immediate_actions_needed": 2,
        "average_prediction_confidence": 0.82,
        "novel_insights_percentage": 0.75
    }}
}}
